def process_sequence(sequence, tree, processed_set, index=0):
    if index >= len(sequence):
        return
    char = sequence[index].lower()
    if char not in processed_set:
        processed_set.add(char)
        tree.insert(char)
    process_sequence(sequence, tree, processed_set, index + 1)

